	rawMap, err := rowsToMap(raw.Raw)
	if err != nil {
		panic(err)
	}
	newMap, err := rowsToMap(rowsNew)
	if err != nil {
		panic(err)
	}

	// Compare raw vs new rows.
	agree := true
	if len(rawMap) != len(newMap) {
		agree = false
	}
	for c, rr := range rawMap {
		nr, ok := newMap[c]
		if !ok || !equalEntryOnSpecFields(rr, nr) {
			agree = false
			break
		}
	}

	// Also compare against prior report.json at finalPath, if it exists.
	if prevBuf, err := os.ReadFile(finalPath); err == nil {
		var prev finalDoc
		if err := json.Unmarshal(prevBuf, &prev); err != nil {
