type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func equalInts(a, b []int) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func equalEntryOnSpecFields(a, b entry) bool {
	if a.Case != b.Case {
		return false
	}
	return equalInts(a.Produced, b.Produced) &&
		equalInts(a.Trace, b.Trace) &&
		equalInts(a.OrderUsed, b.OrderUsed) &&
		a.Packed == b.Packed &&
		a.Grouped == b.Grouped &&
		a.Reuse == b.Reuse
}

func rowsToMap(rows []entry) (map[string]entry, error) {
	m := make(map[string]entry, len(rows))
	for _, r := range rows {
		if r.Case == "" {
			return nil, errors.New("empty case name")
		}
		if _, ok := m[r.Case]; ok {
			return nil, fmt.Errorf("duplicate case in rows: %q", r.Case)
		}
		m[r.Case] = r
	}
	return m, nil
}

func sortedByCase(rows []entry) []entry {
	out := append([]entry(nil), rows...)
	sort.Slice(out, func(i, j int) bool { return out[i].Case < out[j].Case })
	return out
}

